// NH90 Tag Generator - Serviceable (Form C) & Unserviceable (Form B)
// Uses pdf-lib to fill editable PDF form fields with item data

const TAG_TEMPLATES = {
    serviceable: '',
    unserviceable: ''
};

// Field name mapping: item property -> PDF form field name
const SERV_FIELD_MAP = {
    'partNumber':      'Part Number',
    'serialNumber':    'Serial Number',
    'nextInspection':  'SERVICEABLENext Inspection due',
    'description':     'Description',
    'inspector':       'Inspector',
    'workOrder':       'Work Order',
    'inspectorName':   'Name Stamp',
    'logCard':         'Log Card Dain Number If concerned',
    'itemFH':          'SERVICEABLEItem FH',
    'dateOfRemoval':   'Date of Removal',
    'removeFrom':      'SERVICEABLERemove from HC or stock',
    'remarks':         'Remarks'
};

const UNSERV_FIELD_MAP = {
    'date':            'Today',
    'partNumber':      'Part Number',
    'description':     'Description',
    'serialNumber':    'Serial Number',
    'manufacturer':    'Manufacturer',
    'quantity':        'Quantity',
    'removeFrom':      'Remove from HC or stock',
    'logCard':         'Log Card Dain Number If concerned',
    'removedAtFH':     'Removed at Item FH',
    'tsoTsi':          'TSO  TSI If concerned',
    'removedAtCycle':  'Removed at Item Cycle',
    'dateOfRemoval':   'Date of Removal',
    'nameTechnician':  'Name of Technician',
    'reasonForRemoval':'Reason for Removal Fault Code  Description of Failure'
};

let pdfLibLoaded = false;

async function loadPdfLib() {
    if (pdfLibLoaded) return;
    await new Promise((resolve, reject) => {
        const script = document.createElement('script');
        script.src = 'https://cdnjs.cloudflare.com/ajax/libs/pdf-lib/1.17.1/pdf-lib.min.js';
        script.onload = () => { pdfLibLoaded = true; resolve(); };
        script.onerror = reject;
        document.head.appendChild(script);
    });
}

async function generateTag(type, itemData) {
    try {
        await loadPdfLib();
    } catch(e) {
        alert('Cannot load pdf-lib library. Check your internet connection.');
        return;
    }

    const { PDFDocument } = PDFLib;
    
    // Load template PDF
    const templateB64 = TAG_TEMPLATES[type];
    const pdfBytes = Uint8Array.from(atob(templateB64), c => c.charCodeAt(0));
    const pdfDoc = await PDFDocument.load(pdfBytes);
    const form = pdfDoc.getForm();

    if (type === 'serviceable') {
        // Build data object from item
        const data = {
            partNumber:     itemData.partNumber || '',
            serialNumber:   itemData.serialNumber || '',
            nextInspection: itemData.nextInspection || itemData.next18M || itemData.next36M || itemData.next24M || itemData.next60M || '',
            description:    itemData.designation || itemData.description || '',
            inspector:      '',
            workOrder:      itemData.orderRef || itemData.order || '',
            inspectorName:  '',
            logCard:        itemData.logCard || '',
            itemFH:         itemData.flightHours || '',
            dateOfRemoval:  itemData.inspectionDate || new Date().toISOString().split('T')[0],
            removeFrom:     itemData.removeFrom || '',
            remarks:        itemData.comments || ''
        };

        // Fill form fields
        for (const [dataKey, fieldName] of Object.entries(SERV_FIELD_MAP)) {
            try {
                const field = form.getTextField(fieldName);
                if (data[dataKey]) field.setText(String(data[dataKey]));
            } catch(e) { console.warn(`Field not found: ${fieldName}`); }
        }

    } else {
        // Unserviceable
        const today = new Date().toISOString().split('T')[0];
        const data = {
            date:              today,
            partNumber:        itemData.partNumber || '',
            description:       itemData.designation || itemData.description || '',
            serialNumber:      itemData.serialNumber || '',
            manufacturer:      '',
            quantity:          '1',
            removeFrom:        itemData.removeFrom || '',
            logCard:           itemData.logCard || '',
            removedAtFH:       itemData.flightHours || '',
            tsoTsi:            '',
            removedAtCycle:    '',
            dateOfRemoval:     itemData.inspectionDate || today,
            nameTechnician:    '',
            reasonForRemoval:  itemData.reason || itemData.comments || ''
        };

        for (const [dataKey, fieldName] of Object.entries(UNSERV_FIELD_MAP)) {
            try {
                const field = form.getTextField(fieldName);
                if (data[dataKey]) field.setText(String(data[dataKey]));
            } catch(e) { console.warn(`Field not found: ${fieldName}`); }
        }
    }

    // Save - keep form fields editable (do NOT flatten)
    const filledBytes = await pdfDoc.save();
    const blob = new Blob([filledBytes], { type: 'application/pdf' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;

    // Filename: Designation_SN_Serviceable.pdf or Designation_SN_Unserviceable.pdf
    const designation = (itemData.designation || itemData.description || 'Item').replace(/[^a-zA-Z0-9-_ ]/g, '').trim().replace(/\s+/g, '_');
    const sn = (itemData.serialNumber || 'NoSN').replace(/[^a-zA-Z0-9-_]/g, '_');
    const tagType = type === 'serviceable' ? 'Serviceable' : 'Unserviceable';
    a.download = `${designation}_${sn}_${tagType}.pdf`;

    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);

    // Save tag record to database
    const tagRecord = {
        id: Date.now().toString(),
        type: tagType,
        designation: itemData.designation || itemData.description || '',
        partNumber: itemData.partNumber || '',
        serialNumber: itemData.serialNumber || '',
        filename: a.download,
        module: document.title || window.location.pathname.split('/').pop().replace('.html',''),
        generatedAt: new Date().toISOString(),
        generatedBy: localStorage.getItem('currentUser') || 'unknown'
    };

    // Save to Supabase if available
    if (window.ComponentsBayDB) {
        try {
            await ComponentsBayDB.save('generated_tags', tagRecord);
            console.log('📄 Tag saved to DB:', tagRecord.filename);
        } catch(e) {
            console.warn('Tag DB save failed:', e);
        }
    }

    // Always save to localStorage
    let tags = JSON.parse(localStorage.getItem('componentsBayGeneratedTags') || '[]');
    tags.push(tagRecord);
    localStorage.setItem('componentsBayGeneratedTags', JSON.stringify(tags));
    console.log('📄 Tag saved locally:', tagRecord.filename);
}
